import sqlite3, json, sys

conn = sqlite3.connect('/root/.openclaw/workspace/db/state.db')
conn.row_factory = sqlite3.Row
cursor = conn.cursor()

action = sys.argv[1] if len(sys.argv) > 1 else "schema"

if action == "schema":
    cursor.execute("SELECT name FROM sqlite_master WHERE type='table'")
    tables = [r[0] for r in cursor.fetchall()]
    for t in tables:
        cursor.execute(f"PRAGMA table_info({t})")
        cols = [(r[1], r[2]) for r in cursor.fetchall()]
        print(f"TABLE {t}: {cols}")

elif action == "select_projects":
    cursor.execute("SELECT * FROM projects")
    for r in cursor.fetchall():
        print(dict(r))

elif action == "select_tasks":
    cursor.execute("SELECT * FROM tasks")
    for r in cursor.fetchall():
        print(dict(r))

elif action == "select_events":
    cursor.execute("SELECT * FROM progress_events ORDER BY rowid DESC LIMIT 10")
    for r in cursor.fetchall():
        print(dict(r))

elif action == "update_task_done":
    cursor.execute("UPDATE tasks SET status='done' WHERE project='creator-suite' AND task='auth-flow'")
    conn.commit()
    print("Updated auth-flow task to done")

elif action == "update_phase":
    cursor.execute("UPDATE projects SET current_phase='dashboard-integration' WHERE name='creator-suite'")
    conn.commit()
    print("Updated creator-suite current_phase to dashboard-integration")

elif action == "insert_event":
    cursor.execute(
        "INSERT INTO progress_events (project, event, note, timestamp) VALUES (?, ?, ?, datetime('now'))",
        ("creator-suite", "auth-flow completed", "Dashboard integration remains blocked on the API schema.")
    )
    conn.commit()
    print("Inserted progress event")

conn.close()

